import java.util.ArrayList;import java.util.List;import java.util.Map;
final class VisitorPattern{static final class PatternException extends RuntimeException{private final String code;PatternException(String c){super(c);code=c;}String code(){return code;}}interface Node{Object accept(Visitor visitor);}record Equals(String field,Object value)implements Node{public Object accept(Visitor v){return v.visitEquals(this);}}record And(List<Node>children)implements Node{public Object accept(Visitor v){return v.visitAnd(this);}}interface Visitor{Object visitEquals(Equals node);Object visitAnd(And node);}record EvaluateVisitor(Map<String,Object>context)implements Visitor{public Object visitEquals(Equals n){return java.util.Objects.equals(context.get(n.field()),n.value());}public Object visitAnd(And n){for(Node child:n.children())if(!((Boolean)child.accept(this)))return false;return true;}}static final class FieldVisitor implements Visitor{public Object visitEquals(Equals n){return List.of(n.field());}@SuppressWarnings("unchecked")public Object visitAnd(And n){List<String>out=new ArrayList<>();for(Node child:n.children())out.addAll((List<String>)child.accept(this));return out;}}
@SuppressWarnings("unchecked")static Node build(Map<String,Object>v){return switch(String.valueOf(v.get("type"))){case"equals"->new Equals(String.valueOf(v.get("field")),v.get("value"));case"and"->{List<Node>children=new ArrayList<>();for(Map<String,Object>child:(List<Map<String,Object>>)v.getOrDefault("children",List.of()))children.add(build(child));yield new And(children);}default->throw new PatternException("unsupported_node");};}
@SuppressWarnings("unchecked")static Object evaluate(Map<String,Object>input){Node root=build((Map<String,Object>)input.get("tree"));return switch(String.valueOf(input.get("operation"))){case"evaluate"->Map.of("result",root.accept(new EvaluateVisitor((Map<String,Object>)input.getOrDefault("context",Map.of()))));case"collect_fields"->Map.of("fields",root.accept(new FieldVisitor()));default->throw new PatternException("unsupported_operation");};}}
